#include <iostream>
using namespace std;

int main() {
    long long cap[3], milk[3];
    for (int i = 0; i < 3; i++) {
        cin >> cap[i] >> milk[i];
    }

    for (int step = 0; step < 100; step++) {
        int from = step % 3;      // 0->1, 1->2, 2->0
        int to = (step + 1) % 3;

        long long space = cap[to] - milk[to];
        long long pour = min(milk[from], space);
        milk[from] -= pour;
        milk[to] += pour;
    }

    for (int i = 0; i < 3; i++) {
        cout << milk[i] << "\n";
    }
    return 0;
}
